func parseItemsSpec(spec string) ([]store.OrderItem, error) {
	if spec == "" {
		return nil, nil
	}
	parts := strings.Split(spec, ",")
	items := make([]store.OrderItem, 0, len(parts))
	for _, part := range parts {
		part = strings.TrimSpace(part)
		if part == "" {
			continue
		}
		id := part
		qty := 1
		if idx := strings.LastIndex(part, "x"); idx > 0 {
			id = part[:idx]
			parsed, err := strconv.Atoi(part[idx+1:])
			if err != nil || parsed <= 0 {
				return nil, fmt.Errorf("invalid item quantity in %q", part)
			}
			qty = parsed
		}
		items = append(items, store.OrderItem{ItemID: id, ID: id, Quantity: qty})
	}
	return items, nil
}

func subtotalForItems(items []store.OrderItem) float64 {
	var subtotal float64
	for _, item := range items {
		qty := item.Quantity
		if qty <= 0 {
			qty = 1
		}
		subtotal += item.Price * float64(qty)
	}
	return roundMoney(subtotal)
}

func parseTip(tip string, subtotal float64, cfg *config.Config) (float64, error) {
	tip = strings.TrimSpace(tip)
	if tip == "" || tip == "auto" {
		pct := 5.0
		if cfg != nil && cfg.DefaultTipPct > 0 {
			pct = cfg.DefaultTipPct
		}
		return roundMoney(subtotal * pct / 100), nil
	}
	if strings.HasSuffix(tip, "%") {
		pct, err := strconv.ParseFloat(strings.TrimSuffix(tip, "%"), 64)
		if err != nil {
			return 0, fmt.Errorf("invalid --tip percentage %q", tip)
		}
		return roundMoney(subtotal * pct / 100), nil
	}
	amount, err := strconv.ParseFloat(strings.TrimPrefix(tip, "$"), 64)
	if err != nil {
		return 0, fmt.Errorf("invalid --tip amount %q", tip)
	}
	return roundMoney(amount), nil
}

func roundMoney(v float64) float64 {
	return float64(int(v*100+0.5)) / 100
}

func sortedItemTuple(items []store.OrderItem) string {
	ids := make([]string, 0, len(items))
	for _, item := range items {
		id := item.ItemID
		if id == "" {
			id = item.ID
		}
		if id == "" {
			id = item.Name
		}
		qty := item.Quantity
		if qty <= 0 {
			qty = 1
		}
		ids = append(ids, fmt.Sprintf("%sx%d", id, qty))
	}
	sort.Strings(ids)
	return strings.Join(ids, ",")
}

